// frontend/src/components/BottomBar.jsx
import React from "react";

export default function BottomBar({ active = "home", onNavigate }) {
  const Item = ({ id, label }) => {
    const isActive = active === id;
    return (
      <button
        onClick={() => onNavigate?.(id)}
        className={`px-4 py-2 rounded-xl ${isActive ? "bg-purple-600 text-white" : "bg-black/20 text-white"}`}
      >
        {label}
      </button>
    );
  };

  return (
    <nav className="fixed bottom-0 left-0 right-0 z-20">
      <div className="mx-auto max-w-5xl px-4 pb-4">
        <div className="rounded-2xl bg-black/40 backdrop-blur-md p-2 flex gap-2 justify-center">
          <Item id="home" label="Home" />
          <Item id="radar" label="Radar" />
          <Item id="extended" label="Extended" />
        </div>
      </div>
    </nav>
  );
}
